var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"선배님! 뒤 조심하세요!","JPN":"先輩！　後ろに気を付けてください！","ENG":"Mina! On your six!","TWN":"前輩，小心背後！"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"제법이네, 노엘. 실력이 눈에 띄게 늘었어.","JPN":"やるね、ノエル。実力が目に見えて伸びてるじゃない。","ENG":"Not bad, Noelle. Your skills have greatly improved.","TWN":"不錯，洛艾兒。你進步了不少。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"헤헷, 다친 팔로도 늘 앞장서시는 선배님에 비하면 아직 멀었지만요.","JPN":"へへっ、怪我した腕でいつも先頭に立っている先輩と比べると、まだまだですけどね。","ENG":"Heheh, but I'm still nowhere close compared to you. You lead people even with a broken arm.","TWN":"嘿嘿，前輩即使手臂受了傷也依然一馬當先，我比你差遠了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"저 함선에 다가갈수록… 제가 쓰는 힘도 점점 강해지는 느낌이네요.","JPN":"あの艦船に近づくほど……私が使っている力もどんどん強くなっている気がします。","ENG":"The closer I get to that ship... I can feel that the powers I use are also getting stronger.","TWN":"越是接近那艘艦船……我的力量似乎就會變得越強。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"주의하게. 강해진 힘만큼이나 몸이 감당해야 할 부담도 커질 테니.","JPN":"注意した方がいい。力が強くなった分、体にかかる負担も大きくなるはずだ。","ENG":"Take caution. The stronger the power, the more of a burden it will be on your body.","TWN":"要小心。在力量變強的同時，你的身體也要承擔更大的負擔。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그런데, 사장님까지 같이 가도 괜찮겠어?","JPN":"ところで、社長まで一緒に行ってもいいのか？","ENG":"But was it necessary that you tag along, Boss?","TWN":"對了，老闆真的要一起去嗎？"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"스완이 얼마나 강한진 모르지만, 그 여자가 사장님을 노린다면 위험할지도 몰라.","JPN":"スワンがどれほど強いのかはわからないけど、あの女が社長を狙おうとしたら命が危なくなるよ。","ENG":"I don't know how strong Swan is, but you might be in danger if she's after you.","TWN":"我們雖然不知道史旺有多強，但如果她的目標是你，很有可能會陷入危險。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"국제적 유명인사가 날 관중으로 지목했으니, 나도 성의를 보여야지.","JPN":"国際的な有名人が私を観客として名指ししたんだ。こっちも誠意を見せなくては。","ENG":"An international celebrity has appointed me as her audience. I must show some sincerity in return.","TWN":"既然一位國際名人指明我做她的觀眾，我怎能不表現出誠意呢。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"미나 양이야말로 긴장되지 않나?","JPN":"ミナ君こそ、緊張しないのかい？","ENG":"What about you, Mina? Aren't you nervous?","TWN":"反倒是米娜，不緊張嗎？"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"안된다고 한다면 거짓말이지.","JPN":"しない、と言ったら嘘になるね。","ENG":"I'd be lying if I said I wasn't.","TWN":"如果說沒有肯定是在撒謊。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"하지만 세계를 멸망시키려는 음모를 저지하는 일은 전에도 몇 번 겪었으니까.","JPN":"でも、世界を滅ぼそうとする陰謀を阻止することなら、今まで何回も経験したから。","ENG":"But I've had some experience stopping others from destroying the world a few times.","TWN":"但破壞毀滅世界的陰謀這種事，已經不是我第一次經歷了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"오오, 선배님의 이런 멋진 멘트를 직접 듣게 되다니!","JPN":"おお、先輩のカッコいいセリフを直接聞けるとは！","ENG":"Ooh! I can't believe I got to hear Mina's cool line in person!","TWN":"哇喔，竟然親耳聽到了前輩如此帥氣的台詞！"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"저 감동했어요!","JPN":"私、感動しました！","ENG":"It's a dream come true!","TWN":"我好感動！"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"노엘…","JPN":"ノエル……","ENG":"Noelle...","TWN":"洛艾兒……"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"넌 겁나지 않아?","JPN":"あなたは怖くないの？","ENG":"Aren't you even a little scared?","TWN":"你不害怕嗎？"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"이건 목숨이 걸린 일이야. 태스크포스에 갓 입사한 시골소녀가 감당할만한 일은 아니라고.","JPN":"命がかかっているんだ。タスクフォースに入社したばかりの田舎娘に務まるような仕事ではないんだよ。","ENG":"You're risking your life here. This isn't something that a TASKFORCE rookie can handle.","TWN":"這是生死攸關的時刻，不是剛加入特遣勢力的小女孩所能承受的。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};